import{_ as p}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as c,c as t,a,b as e,d as l,e as o,r as i}from"./app.7f917e11.js";const d={},r=o('<h2 id="前言" tabindex="-1"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h2><p>公司使用 uniapp 开发的 App 端项目在红米 Note11T Pro 中出现了拍照后闪退的问题，也是折腾了挺久才研究出原因和解决方案，在这里记录和分享。</p><h2 id="调试分析" tabindex="-1"><a class="header-anchor" href="#调试分析" aria-hidden="true">#</a> 调试分析</h2><p>首先可以肯定的是并非代码的问题，在调用拍摄 Api（uni.chooseImage）前、成功回调、失败回调中都打了断点，除了拍摄前的断点进入了，成功和失败回调是没有进入的，而且闪退只在少部分机型上出现，不是必现的行为。</p><p>在网上查了一些 uniapp 拍照闪退的相关资料，可以排除的原因有</p><ul><li>没有配置权限</li><li>拍照像素过大，GPU 渲染崩溃 <ul><li>按下拍摄键还没确认的时候应用其实就已经闪退了，也就不存在 GPU 渲染问题</li></ul></li></ul><p>既然前端代码没有问题，那我们就得往低一层去调试分析了，使用离线打包配置，在 as 中运行项目到真机并开启 logcat：</p><p><img src="http://qkc148.bvimg.com/18470/fbcb8b1839ebcc41.png" alt="20231203154344" loading="lazy"></p><p>目前的日志有点多，包含了整个系统的日志输出，所以我们需要做个过滤：</p><p><img src="http://qkc148.bvimg.com/18470/68142fb3405445ec.png" alt="20231203155600" loading="lazy"></p>',10),s=a("code",null,"com.android.simple",-1),g=a("code",null,"warn",-1),h=a("code",null,"error",-1),m={href:"https://developer.android.com/studio/debug/logcat?hl=zh-cn",target:"_blank",rel:"noopener noreferrer"},u=a("p",null,"接下来我们需要在设备（真机、模拟器）上进行操作来复现闪退的行为，然后查找可疑的 crash 日志。",-1),b=a("p",null,[a("img",{src:"https://qkc148.bvimg.com/18470/b9a548df1c946bad.gif",alt:"a51f4013-6f9a-4a80-a69e-10a88a34f338",loading:"lazy"})],-1),_=a("p",null,"这样操作了几次，虽然会复现闪退行为，但并没有找到相关的 crash 日志，得到的信息只有：按下拍摄键后应用进程被结束。",-1),f=a("p",null,[a("img",{src:"http://qkc148.bvimg.com/18470/838664f464be5ba5.png",alt:"20231203173635",loading:"lazy"})],-1),v=a("p",null,"到这里信息基本算是断了，但是没有 crash 日志，闪退的可能性降低了，那是不是系统回收了应用资源呢？我们搜索对应的机型 + 关键词：",-1),k=a("p",null,[a("img",{src:"http://qkc148.bvimg.com/18470/42e92f63155fcca3.png",alt:"20231203174504",loading:"lazy"})],-1),y={href:"https://blog.csdn.net/huyongl1989/article/details/49333953",target:"_blank",rel:"noopener noreferrer"},q={href:"https://blog.csdn.net/u013474104/article/details/54666820",target:"_blank",rel:"noopener noreferrer"},z=a("p",null,"通过上面的两篇文章，我们可以发现一些共同点：",-1),x=a("ul",null,[a("li",null,"调用系统相机进行拍摄"),a("li",null,"拍摄时应用进入后台，此时可能会被系统回收资源")],-1),A=a("p",null,"这两篇文章的问题与我们目前经历的很像，都是调用系统相机拍摄后应用被结束了进程，那么很大的可能是应用进入后台后被系统回收了资源。",-1),N=a("p",null,"如果是这样的话那我们需要降低应用进入后台后被系统回收资源的几率，也就是保活，为此找到了一篇 Android 保活相关的文章：",-1),j={href:"https://cloud.tencent.com/developer/article/1784046",target:"_blank",rel:"noopener noreferrer"},P=o(`<p>从这篇文章里知道了一个关键的信息：应用后台优先级 — oom_adj 值。</p><p>这个值是反映进程的优先级的，在系统内存不足时，会根据这个值去决定将哪些进程回收（kill），值越低表示优先级越高，越不可能被回收资源。常见的值有：</p><ul><li>0：前台进程，应用目前在前台运行</li><li>1：可感知进程，比如播放音乐，通知栏有可交互的控件</li><li>负数：属于系统级别的进程</li></ul><p>这个值是根据你的应用状态实时变化的，可以通过以下命令查看你的应用 oom_adj 值：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>- adb shell <span class="token string">&quot;ps|grep your package name&quot;</span>

- adb shell
- <span class="token function">cat</span> /proc/pid/oom_adj
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>前台</p><p><img src="http://qkc148.bvimg.com/18470/413a08249ae5752d.png" alt="20231203181714" loading="lazy"></p><p>后台</p><p><img src="http://qkc148.bvimg.com/18470/2f6c122f1441d7b8.png" alt="20231203182001" loading="lazy"></p><p>可以发现什么也没做的话（如果开通了厂商提供的通知服务，如 MiPush，会开启一个专属的通知进程，可以提升应用的后台优先级，但是测试发现红米 Note11T Pro Android13 里这个通知进程也很容易被 kill）应用进入后台时的优先级是很低的，调用拍摄又是个消耗大量内存的行为，也就不奇怪会出现应用被回收资源的问题了。</p><h2 id="uniapp-android-原生插件开发" tabindex="-1"><a class="header-anchor" href="#uniapp-android-原生插件开发" aria-hidden="true">#</a> uniapp Android 原生插件开发</h2>`,11),T={href:"https://cloud.tencent.com/developer/article/1784046",target:"_blank",rel:"noopener noreferrer"},M={href:"https://nativesupport.dcloud.net.cn/NativePlugin/course/android.html",target:"_blank",rel:"noopener noreferrer"},S=a("p",null,"关于环境的配置就不过多介绍，需要的可以看下面这篇文章：",-1),U={href:"https://blog.csdn.net/weixin_43449246/article/details/120486710",target:"_blank",rel:"noopener noreferrer"},V=o('<h3 id="module-配置" tabindex="-1"><a class="header-anchor" href="#module-配置" aria-hidden="true">#</a> module 配置</h3><p>我们先新建一个 module：</p><p><img src="http://qkc148.bvimg.com/18470/d7a095efa0aea2c5.png" alt="20231203184854" loading="lazy"></p><p><img src="http://qkc148.bvimg.com/18470/d31de5eba43dbdf7.png" alt="20231203185003" loading="lazy"></p><p><img src="http://qkc148.bvimg.com/18470/6597dcbfee698d99.png" alt="20231203185030" loading="lazy"></p><p>可能会出现报错，我们直接 cv uniapp Android SDK 中 <code>richalert</code> 的 <code>.gradle</code> 配置并点击 <code>Try Again</code>：</p><p><img src="http://qkc148.bvimg.com/18470/28a0f9f0d40a9134.png" alt="20231203185332" loading="lazy"></p><p>如果出现错误 <code>package name not found</code>，我们直接点击进入对应的文件：</p><p><img src="http://qkc148.bvimg.com/18470/99dd1e09687a59ae.png" alt="20231203185630" loading="lazy"></p><p>添加自己的包名并再次尝试：</p><p><img src="http://qkc148.bvimg.com/18470/ab110a1b3f4a898e.png" alt="20231203185801" loading="lazy"></p><p>删除这两个文件：</p><p><img src="http://qkc148.bvimg.com/18470/58958d21727c0d16.png" alt="20231203190230" loading="lazy"></p><p>新建一个 uniapp module 类供其调用：</p><p><img src="http://qkc148.bvimg.com/18470/863abb6f2799ee74.png" alt="20231203190442" loading="lazy"></p><p><img src="http://qkc148.bvimg.com/18470/c49c985f73c23e87.png" alt="20231203190548" loading="lazy"></p><p>根据文档，这个需要和 uniapp 打交道的类需要继承 <code>UniModule</code>:</p><p><img src="http://qkc148.bvimg.com/18470/10a98f2b8bde970f.png" alt="20231203190821" loading="lazy"></p><p>我们可以定义在前端代码中调用的方法，这个方法需要加上 <code>@UniJSMethod(uiThread = boolean)</code> 注解，<code>uiThread</code> 标识是否运行在 ui 线程：</p><p><img src="http://qkc148.bvimg.com/18470/20b1297267f2ad3a.png" alt="20231203191508" loading="lazy"></p><p>然后需要在 uniapp 的配置中配置这个类，并在主模块的 <code>.gradle</code> 配置中添加依赖，然后编译：</p><p><img src="http://qkc148.bvimg.com/18470/52fe698c8e25cd4b.png" alt="20231203191950" loading="lazy"></p><p><img src="http://qkc148.bvimg.com/18470/4c6e8e64238f12df.png" alt="20231203192121" loading="lazy"></p><p>现在可以试试是否可以调用：</p><p><img src="http://qkc148.bvimg.com/18470/ccb3cb266ecd0190.png" alt="20231203192749" loading="lazy"></p><p><img src="http://qkc148.bvimg.com/18470/1516bfa68ccca8bd.png" alt="20231203193312" loading="lazy"></p><h3 id="保活功能实现" tabindex="-1"><a class="header-anchor" href="#保活功能实现" aria-hidden="true">#</a> 保活功能实现</h3><p>新建一个类并继承自 <code>Service</code>:</p><p><img src="http://qkc148.bvimg.com/18470/7e36314fe89a40e0.png" alt="20231203194231" loading="lazy"></p><p>在这个类中创建一个前台服务：</p><p><img src="http://qkc148.bvimg.com/18470/d4d98ac04f9688c5.png" alt="20231203202148" loading="lazy"></p><p>在 <code>AndroidManifest.json</code> 中注册服务并添加前台服务权限：</p><p><img src="http://qkc148.bvimg.com/18470/ada4719a9340b94f.png" alt="20231203202427" loading="lazy"></p><p>修改之前的 <code>startForeground</code> 方法，开启一个服务：</p><p><img src="http://qkc148.bvimg.com/18470/376141bc8fdc1c30.png" alt="20231203202324" loading="lazy"></p><p>得到的效果如下：</p><p><img src="http://qkc148.bvimg.com/18470/c4bc6468fd9138aa.gif" alt="edd3fa92-afe3-4c75-af14-39240c39e1d0" loading="lazy"></p><p>查看应用后台时的 oom_adj 值确实变小了，也没有再次测到拍照闪退的问题，现在可以肯定是系统回收资源导致的了：</p><p><img src="http://qkc148.bvimg.com/18470/acd8e6913b5a76f5.png" alt="20231203204159" loading="lazy"></p><p>可以使用手机的开发者选项，开启后台进程限制，选择最多不超过两个后台进程，然后开启你的应用和两个额外的应用，在这三个应用间切换，你会发现被杀死的总是另外两个应用，你的应用是一直存活的。</p><h2 id="后话" tabindex="-1"><a class="header-anchor" href="#后话" aria-hidden="true">#</a> 后话</h2><p>本来到这里以为已经结束了，谁知道同事说以前做过保活功能，但是被应用商店给打回了，目前国内对后台运行、自启动、关联启动基本是 0 容忍。</p><p>也尝试过双进程守护等保活实现，但是现在的系统对于后台服务在后台运行超过一定时间后会直接杀死，可以说目前国内想实现保活基本是不可能了。</p><p>目前还没有更新发版，不确定这种轻量级的保活能不能审核通过；有大佬提供过一种思路：不调用系统相机，自定义拍照页面来完成拍照功能。这样应用还是在前台的，也就不会被系统杀死了。</p>',44),B={href:"https://juejin.cn/pin/7306192146767446031",target:"_blank",rel:"noopener noreferrer"};function E(I,L){const n=i("ExternalLinkIcon");return c(),t("div",null,[r,a("p",null,[e("过滤包名为 "),s,e(" 且等级为 "),g,e(" 和 "),h,e(" 的日志输出。完整的过滤语法看官网文档 "),a("a",m,[e("使用 Logcat 查看日志"),l(n)]),e(" 。")]),u,b,_,f,v,k,a("ul",null,[a("li",null,[a("a",y,[e("红米Note调用系统相机拍照后应用崩溃问题分析解决"),l(n)])]),a("li",null,[a("a",q,[e("如何保证android程序进程不到万不得已的情况下，不会被结束"),l(n)])])]),z,x,A,N,a("ul",null,[a("li",null,[a("a",j,[e("Android实现进程保活方案解析"),l(n)])])]),P,a("p",null,[e("既然知道了可能的原因，我们就需要有针对的去解决，这里我采用 "),a("a",T,[e("Android实现进程保活方案解析"),l(n)]),e(" 中的前台服务方案，开发一个 Android 原生插件，尝试提升应用的优先级。参考 uniapp 文档：")]),a("ul",null,[a("li",null,[a("a",M,[e("Android 插件开发教程"),l(n)])])]),S,a("ul",null,[a("li",null,[a("a",U,[e("记录【未配置appkey或配置错误】安卓开发uniapp的原生插件的步骤及避坑"),l(n)])])]),V,a("p",null,[e("最后附上另外一位热心大佬和我的沟通讨论："),a("a",B,[e("应用保活讨论"),l(n)])])])}const C=p(d,[["render",E],["__file","flashback_analysis_and_develop_native_plug.html.vue"]]);export{C as default};
